import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  Typography,
  TextField,
  Button,
  IconButton,
  InputAdornment,
  Link
} from '@mui/material';
import { Visibility, VisibilityOff } from '@mui/icons-material';
import { Link as RouterLink, useNavigate, useLocation } from 'react-router-dom';
import { supabase } from '../supabase';
import SafePassImage from '../assets/logo.svg';
import '../styles/styles.css';

const Login = ({ notificationsRef }) => {
  const [showPassword, setShowPassword] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => {
    if (location.state?.logoutMessage) {
      notificationsRef.current.showSnackbar(location.state.logoutMessage, 'success');
      navigate(location.pathname, { replace: true, state: {} });
    }
  }, [location, navigate, notificationsRef]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      const { data: profile, error: profileError } = await supabase
        .from('profiles')
        .select('email')
        .eq('username', username)
        .single();

      if (profileError || !profile) {
        notificationsRef.current.showSnackbar('Wrong username or password.', 'error');
        setLoading(false);
        return;
      }

      const { data, error } = await supabase.auth.signInWithPassword({
        email: profile.email,
        password,
      });

      if (error || !data.user) {
        notificationsRef.current.showSnackbar('Wrong username or password.', 'error');
        setLoading(false);
        return;
      }

      localStorage.setItem('user_id', data.user.id);
      localStorage.setItem('username', username);

      notificationsRef.current.showSnackbar(`Welcome back, ${username}!`, 'success');
      setTimeout(() => window.location.reload(), 1000);
    } catch (err) {
      notificationsRef.current.showSnackbar('Something went wrong.', 'error');
      setLoading(false);
    }
  };

  return (
    <Box className="safeContainer">
      <Paper className="safePaper" elevation={3}>
        <Box className="safeHeader">
          <Box component="img" src={SafePassImage} alt="SafePass" className="safeLogo" />
          <Typography component="h1" variant="h5" className="safeTitle">
            Welcome to SafePass
          </Typography>
          <Typography variant="body2" color="text.secondary" align="center">
            All passwords under your control
          </Typography>
        </Box>

        <form onSubmit={handleSubmit} noValidate style={{ width: '100%' }}>
          <TextField
            required fullWidth margin="normal" label="Username"
            autoComplete="username" autoFocus value={username}
            onChange={(e) => setUsername(e.target.value)}
            InputProps={{ className: 'safeTextField' }}
          />

          <TextField
            required fullWidth margin="normal" label="Password"
            type={showPassword ? 'text' : 'password'}
            autoComplete="current-password" value={password}
            onChange={(e) => setPassword(e.target.value)}
            InputProps={{
              className: 'safeTextField',
              endAdornment: (
                <InputAdornment position="end">
                  <IconButton onClick={() => setShowPassword((p) => !p)} onMouseDown={(e) => e.preventDefault()} edge="end">
                    {showPassword ? <VisibilityOff /> : <Visibility />}
                  </IconButton>
                </InputAdornment>
              ),
            }}
          />

          <Button type="submit" fullWidth variant="contained" className="safeSubmitButton" disabled={loading}>
            {loading ? 'Signing in...' : 'Sign In'}
          </Button>

          <Box className="safeLinkContainer">
            <Link component={RouterLink} to="/register" variant="body2" className="safeLink">Sign Up</Link>
            <Link component={RouterLink} to="/forgot-password" variant="body2" className="safeLink">Forgot Password?</Link>
          </Box>
        </form>
      </Paper>
    </Box>
  );
};

export default Login;