import React, { useState } from 'react';
import {
  Container,
  Box,
  Paper,
  Typography,
  TextField,
  Button,
  IconButton,
  InputAdornment,
  Fade
} from '@mui/material';
import { Visibility, VisibilityOff, ArrowBack } from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../supabase';
import '../styles/styles.css';

const Register = ({ notificationsRef }) => {
  const [username, setUsername] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const errorMessages = {
    usernameRequired: 'Enter a username.',
    emailRequired: 'Enter your email.',
    passwordRequired: 'Enter a password.',
    confirmPasswordRequired: 'Confirm your password.',
    passwordsMismatch: "Passwords don't match.",
    invalidUsername: 'Lowercase letters and numbers only.',
    usernameExists: 'Username already taken.',
    registrationSuccess: 'Account created! Check your email to confirm.',
    serverError: 'Something went wrong.',
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!username) { notificationsRef.current.showSnackbar(errorMessages.usernameRequired, 'error'); return; }
    if (!email) { notificationsRef.current.showSnackbar(errorMessages.emailRequired, 'error'); return; }
    if (!password) { notificationsRef.current.showSnackbar(errorMessages.passwordRequired, 'error'); return; }
    if (!confirmPassword) { notificationsRef.current.showSnackbar(errorMessages.confirmPasswordRequired, 'error'); return; }
    if (password !== confirmPassword) { notificationsRef.current.showSnackbar(errorMessages.passwordsMismatch, 'error'); return; }
    if (!/^[a-z0-9]+$/.test(username)) { notificationsRef.current.showSnackbar(errorMessages.invalidUsername, 'error'); return; }

    setLoading(true);

    try {
      const { data: existing } = await supabase
        .from('profiles')
        .select('id')
        .eq('username', username)
        .single();

      if (existing) {
        notificationsRef.current.showSnackbar(errorMessages.usernameExists, 'error');
        setLoading(false);
        return;
      }

      const { data, error } = await supabase.auth.signUp({
        email,
        password,
        options: {
          data: { username },
        },
      });

      if (error || !data.user) {
        notificationsRef.current.showSnackbar(error?.message || errorMessages.serverError, 'error');
        setLoading(false);
        return;
      }

      const { error: profileError } = await supabase
        .from('profiles')
        .insert([{ id: data.user.id, username, email, avatar_url: '' }]);

      if (profileError) {
        notificationsRef.current.showSnackbar(errorMessages.serverError, 'error');
        setLoading(false);
        return;
      }

      notificationsRef.current.showSnackbar(errorMessages.registrationSuccess, 'success');
      setTimeout(() => navigate('/'), 3000);
    } catch (err) {
      notificationsRef.current.showSnackbar(errorMessages.serverError, 'error');
      setLoading(false);
    }
  };

  const handleClickShowPassword = () => setShowPassword((prev) => !prev);
  const handleMouseDownPassword = (event) => event.preventDefault();

  return (
    <Box className="registerContainer">
      <IconButton onClick={() => navigate(-1)} className="registerBackButton" color="primary">
        <ArrowBack />
      </IconButton>

      <Container component="main" maxWidth="xs" className="registerMainContainer">
        <Fade in={true} timeout={1000}>
          <Paper elevation={3} className="registerPaper">
            <Box className="registerTitleBox">
              <Typography component="h1" variant="h5" className="registerTitle">
                Register
              </Typography>
            </Box>

            <form onSubmit={handleSubmit} noValidate>
              <TextField
                required
                fullWidth
                margin="normal"
                label="Username"
                autoComplete="username"
                autoFocus
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                InputProps={{ className: 'registerTextField' }}
              />

              <TextField
                required
                fullWidth
                margin="normal"
                label="Email"
                type="email"
                autoComplete="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                InputProps={{ className: 'registerTextField' }}
              />

              <TextField
                required
                fullWidth
                margin="normal"
                label="Password"
                type={showPassword ? 'text' : 'password'}
                autoComplete="new-password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                InputProps={{
                  className: 'registerTextField',
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton onClick={handleClickShowPassword} onMouseDown={handleMouseDownPassword} edge="end">
                        {showPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
              />

              <TextField
                required
                fullWidth
                margin="normal"
                label="Confirm Password"
                type={showPassword ? 'text' : 'password'}
                autoComplete="new-password"
                value={confirmPassword}
                onChange={(e) => setConfirmPassword(e.target.value)}
                InputProps={{
                  className: 'registerTextField',
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton onClick={handleClickShowPassword} onMouseDown={handleMouseDownPassword} edge="end">
                        {showPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
              />

              <Button
                type="submit"
                fullWidth
                variant="contained"
                className="registerSubmitButton"
                disabled={loading}
              >
                {loading ? 'Registering...' : 'Register'}
              </Button>
            </form>
          </Paper>
        </Fade>
      </Container>
    </Box>
  );
};

export default Register;