import React, { useState } from 'react';
import {
  Container,
  Box,
  Paper,
  Typography,
  TextField,
  Button,
  IconButton,
  Fade
} from '@mui/material';
import { ArrowBack } from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../supabase';
import '../styles/styles.css';

const ForgotPassword = ({ notificationsRef }) => {
  const [email, setEmail] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!email) {
      notificationsRef.current.showSnackbar('Enter your email.', 'error');
      return;
    }

    setLoading(true);

    const redirectTo = window.location.hostname === 'localhost'
      ? 'http://localhost:3000/SafePass/reset-password'
      : 'https://andresnalegre.github.io/SafePass/reset-password';

    const { error } = await supabase.auth.resetPasswordForEmail(email, {
      redirectTo,
    });

    if (error) {
      notificationsRef.current.showSnackbar('Something went wrong.', 'error');
      setLoading(false);
      return;
    }

    notificationsRef.current.showSnackbar('Check your email for the reset link.', 'success');
    setLoading(false);
  };

  return (
    <Box className="resetContainer">
      <IconButton onClick={() => navigate(-1)} className="resetBackButton" color="primary">
        <ArrowBack />
      </IconButton>

      <Container component="main" maxWidth="xs" className="resetMainContainer">
        <Fade in={true} timeout={1000}>
          <Paper elevation={3} className="resetPaper">
            <Box className="resetTitleBox">
              <Typography component="h1" variant="h5" className="resetTitle">
                Reset Password
              </Typography>
            </Box>

            <Typography variant="body2" color="text.secondary" align="center" mb={2}>
              Enter your email and we'll send you a reset link.
            </Typography>

            <form onSubmit={handleSubmit} noValidate>
              <TextField
                required
                fullWidth
                margin="normal"
                label="Email"
                type="email"
                autoComplete="email"
                autoFocus
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                InputProps={{ className: 'resetTextField' }}
              />

              <Button
                type="submit"
                fullWidth
                variant="contained"
                className="resetSubmitButton"
                disabled={loading}
              >
                {loading ? 'Sending...' : 'Send Reset Link'}
              </Button>
            </form>
          </Paper>
        </Fade>
      </Container>
    </Box>
  );
};

export default ForgotPassword;