import React, { useState, useEffect } from 'react';
import {
  Container,
  Box,
  Paper,
  Typography,
  TextField,
  Button,
  IconButton,
  InputAdornment,
  Fade
} from '@mui/material';
import { Visibility, VisibilityOff } from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../supabase';
import '../styles/styles.css';

const ResetPassword = ({ notificationsRef }) => {
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [ready, setReady] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    const { data: { subscription } } = supabase.auth.onAuthStateChange((event) => {
      if (event === 'PASSWORD_RECOVERY') {
        setReady(true);
      }
    });
    return () => subscription.unsubscribe();
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!newPassword) {
      notificationsRef.current.showSnackbar('Enter a new password.', 'error');
      return;
    }
    if (newPassword !== confirmPassword) {
      notificationsRef.current.showSnackbar("Passwords don't match.", 'error');
      return;
    }

    setLoading(true);

    const { error } = await supabase.auth.updateUser({ password: newPassword });

    if (error) {
      notificationsRef.current.showSnackbar('Something went wrong.', 'error');
      setLoading(false);
      return;
    }

    notificationsRef.current.showSnackbar('Password updated!', 'success');
    setTimeout(() => navigate('/'), 2000);
  };

  if (!ready) {
    return (
      <Box className="resetContainer">
        <Container component="main" maxWidth="xs" className="resetMainContainer">
          <Paper elevation={3} className="resetPaper">
            <Typography align="center" color="text.secondary">
              Validating reset link...
            </Typography>
          </Paper>
        </Container>
      </Box>
    );
  }

  return (
    <Box className="resetContainer">
      <Container component="main" maxWidth="xs" className="resetMainContainer">
        <Fade in={true} timeout={1000}>
          <Paper elevation={3} className="resetPaper">
            <Box className="resetTitleBox">
              <Typography component="h1" variant="h5" className="resetTitle">
                New Password
              </Typography>
            </Box>

            <form onSubmit={handleSubmit} noValidate>
              <TextField
                required
                fullWidth
                margin="normal"
                label="New Password"
                type={showPassword ? 'text' : 'password'}
                autoComplete="new-password"
                autoFocus
                value={newPassword}
                onChange={(e) => setNewPassword(e.target.value)}
                InputProps={{
                  className: 'resetTextField',
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton onClick={() => setShowPassword((p) => !p)} edge="end">
                        {showPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
              />

              <TextField
                required
                fullWidth
                margin="normal"
                label="Confirm Password"
                type={showPassword ? 'text' : 'password'}
                autoComplete="new-password"
                value={confirmPassword}
                onChange={(e) => setConfirmPassword(e.target.value)}
                InputProps={{
                  className: 'resetTextField',
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton onClick={() => setShowPassword((p) => !p)} edge="end">
                        {showPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
              />

              <Button
                type="submit"
                fullWidth
                variant="contained"
                className="resetSubmitButton"
                disabled={loading}
              >
                {loading ? 'Updating...' : 'Update Password'}
              </Button>
            </form>
          </Paper>
        </Fade>
      </Container>
    </Box>
  );
};

export default ResetPassword;